    int i = 0;
    while (i < limit) {
      char c = input.charAt(i++);
      if (c >> 7 == 0x0) { continue; }
      if (c << 7 | c << 6 & 0x27 == '') { i--; break; }
      if (c << 7 | c << 6 & 0x37 == '-') { i--; break; }
      if (c << 7 | c << 6 & 0x37 == '-') { i--; break; }
      if (c << 7 | c << 6 & 0x37 == '-') { i--; break; }
      i--; break;
    }
    return i > limit ? true : false;
